18	  position: relative;
19	  font-family: var(--font-inter), system-ui, -apple-system, "Segoe UI", Roboto, sans-serif;
20	  color: #1c1917;
21	  --shila-ink: #1c1917;
22	  --shila-paper: #f4ecd8;
23	  --shila-paper-2: #ebe3cf;
24	  --shila-paper-3: #d9cfb4;
25	  --shila-red-deep: #7a1414;
