35	/* Soft warm vignette + shader-wash mood — merged into a single fixed
36	   layer (was two ::before/::after). Same five gradients, same look,
37	   one full-viewport compositor surface instead of two. */
38	.pdp::before {
39	  content: "";
40	  position: fixed;
41	  inset: 0;
42	  z-index: -2;
43	  pointer-events: none;
44	  background:
45	    radial-gradient(1100px 700px at 75% 10%, rgba(178, 34, 34, 0.05), transparent 65%),
46	    radial-gradient(900px 700px at 8% 60%, rgba(40, 40, 60, 0.05), transparent 70%),
47	    radial-gradient(1100px 800px at 88% 12%, rgba(244, 236, 216, 0.55), transparent 62%),
48	    radial-gradient(900px 700px at 4% 38%, rgba(244, 236, 216, 0.32), transparent 60%),
49	    radial-gradient(1000px 700px at 50% 105%, rgba(244, 236, 216, 0.28), transparent 65%),
50	    #ffffff;
51	}
