53	/* Background art layer (scrolls with page) */
54	.pdpBg {
55	  position: absolute;
56	  inset: 0;
57	  z-index: 0;
58	  pointer-events: none;
59	  overflow: hidden;
60	  /* Single radial-gradient mask feathers all four edges in one pass.
61	     The previous double-linear + mask-composite: intersect forced an
62	     extra compositor flatten on every scroll frame across the wrapper
63	     holding all 4 multiply-blended bg arts. Same edge-fade visual,
64	     one composite pass instead of two. */
65	  mask-image: radial-gradient(ellipse 96% 98% at 50% 50%, black 78%, transparent 100%);
66	  -webkit-mask-image: radial-gradient(ellipse 96% 98% at 50% 50%, black 78%, transparent 100%);
67	}
68	.pdp > :not(.pdpBg):not(.ornamentCorner) {
69	  position: relative;
70	  z-index: 1;
