/* LIGHTBOX */
.lightbox {
  position: fixed;
  inset: 0;
  /* dvh keeps the lightbox at full visible viewport height on mobile so the
     close button isn't hidden under the URL bar, while inset:0 still wins
     on browsers that don't support dvh. */
  height: 100dvh;
  width: 100vw;
  z-index: 200;
  background: rgba(15, 15, 15, 0.92);
  display: none;
  align-items: center;
  justify-content: center;
  padding: 2rem;
  backdrop-filter: blur(10px);
}
.lightboxOpen {
