/* =============================================================
   reviews.css — styles for the Reviews module
   All classes namespaced with `.rv-` (+ .reviews-section root).
   ============================================================= */

/* -------- Brand tokens used by this module --------
   These are scoped to .reviews-section so the module is fully
   self-contained. If your app already defines these on :root,
   you can delete this block.
*/
.reviews-section {
  --shila-ink:        #1c1917;
  /* B&G theme: warm paper surface flattened to a soft neutral gray so the
     active-detail panel and chip backgrounds tonally match the rest of the PDP. */
  --shila-paper:      #f5f5f5;
  --shila-gray-2:     #444444;
  --shila-gray-3:     #6b6b6b;
  --shila-gray-4:     #9a9a9a;
  /* B&G theme: collapse the colored accents (deep red + bronze) into the
     ink/gray scale. Stars, bar fills, active borders, focus rings, eyebrow,
     verified badge, see-all link — all driven by these two tokens — now read
     as a tonal continuation of the rest of the PDP. */
  --shila-red-deep:   #1c1917;
  --shila-bronze:     #6b6b6b;

  --font-display: 'Trajan Pro', 'Cinzel', 'Times New Roman', serif;
  /* font-body falls back to inherit (page body font) */
}

