file.content:
@import "tailwindcss";

:root {
  --background: #ffffff;
  --foreground: #171717;
}

@media (prefers-color-scheme: dark) {
  :root {
    --background: #0a0a0a;
    --foreground: #ededed;
  }
}

html,
body {
  max-width: 100vw;
  overflow-x: hidden;
  width: 100%;
  margin: 0;
  padding: 0;
}

body {
  color: var(--foreground);
  background: #ffffff;
  font-family: Arial, Helvetica, sans-serif;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

* {
  box-sizing: border-box;
  padding: 0;
  margin: 0;
}

a {
  color: inherit;
  text-decoration: none;
}

@media (prefers-color-scheme: dark) {
  html {
    color-scheme: dark;
  }
}

/* Out-of-focus wash for full-screen overlays (lightbox, review drawer, etc).
   When `body.overlay-blur` is on, every direct child of <body> except the
   overlay itself (marked with data-overlay) gets a real CSS `filter: blur`,
   not `backdrop-filter` — which the PDP's mix-blend-mode + stacking context
   was silently suppressing. Saturate dip pushes the haze toward neutral so
   the focused dialog/image owns the eye. Pointer-events disabled so the
   page underneath can't be interacted with by accident. */
body.overlay-blur > *:not([data-overlay]) {
  filter: blur(2px);
  transition: filter 0.2s ease;
  pointer-events: none;
}

